import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Save, Send, Plus, Trash2 } from 'lucide-react';
import { getPresupuesto, createPresupuesto, updatePresupuesto, getClientes, getMateriales, convertirAOrden } from '../../services/api';
import { formatCurrency, formasPago } from '../../utils/formatters';
import Loading from '../common/Loading';

const SECTORES_SUGERIDOS = ['Mesada', 'Isla', 'Barra', 'Vanitory', 'Escalón', 'Revestimiento', 'Antepecho', 'Otro'];

const ADICIONALES_SUGERIDOS = [
  'Apertura y pegado de pileta', 'Apertura pileta apoyo', 'Apertura toma corriente',
  'Apertura anafe', 'Terminación canto', 'TERMINACIÓN FRENTE', 'Zócalos', 'Faldón', 'Escurridor',
  'Agujero grifería', 'Agujero dispenser', 'Transporte', 'Descarga', 'Otro'
];

const TIPOS_FRENTE = ['INGLETADO 45°', 'CLÁSICO RASADO', 'CLÁSICO HUNDIDO', 'DOBLE RASADO', 'DOBLE HUNDIDO'];

function emptyItem(precio_m2 = 0) {
  return { sector: '', zocalo: '', frente: '', largo: 0, ancho: 0, m2: 0, cantidad: 1, precio_m2, subtotal: 0 };
}

function emptyAdicional() {
  return { concepto: '', detalle: '', cantidad: 1, precio_unitario: 0, subtotal: 0 };
}

export default function PresupuestoForm() {
  const { id } = useParams();
  const navigate = useNavigate();
  const isEdit = !!id;
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [clientes, setClientes] = useState([]);
  const [materiales, setMateriales] = useState([]);
  const [materialOtro, setMaterialOtro] = useState(false);

  const [form, setForm] = useState({
    cliente_id: '', material: '', material_precio_m2: 0, color_tipo: '', espesor: '',
    subtotal_materiales: 0, subtotal_servicios: 0, total: 0,
    forma_pago: '', validez: '10 días', entrega_aproximada: '',
    fecha_estimada_entrega: '', condiciones_comerciales: '', observaciones: '',
  });

  const [items, setItems] = useState([emptyItem(0)]);
  const [adicionales, setAdicionales] = useState([]);

  useEffect(() => {
    Promise.all([
      getClientes(),
      getMateriales({ limit: 500 }),
    ]).then(([clientesRes, matRes]) => {
      setClientes(clientesRes.data);
      setMateriales(matRes.data);
    });
    if (id) {
      getPresupuesto(id).then((res) => {
        const d = res.data;
        setForm({
          cliente_id: d.cliente_id || '',
          material: d.material || '', material_precio_m2: d.material_precio_m2 || 0,
          color_tipo: d.color_tipo || '', espesor: d.espesor || '',
          subtotal_materiales: d.subtotal_materiales || 0,
          subtotal_servicios: d.subtotal_servicios || 0, total: d.total || 0,
          forma_pago: d.forma_pago || '', validez: d.validez || '10 días',
          entrega_aproximada: d.entrega_aproximada || '',
          fecha_estimada_entrega: d.fecha_estimada_entrega ? d.fecha_estimada_entrega.slice(0, 10) : '',
          condiciones_comerciales: d.condiciones_comerciales || '',
          observaciones: d.observaciones || '',
        });
        if (d.items && d.items.length) {
          setItems(d.items);
        } else {
          setItems([emptyItem(d.material_precio_m2 || 0)]);
        }
        setAdicionales(d.adicionales || []);
        setLoading(false);
      });
    }
  }, [id]);

  useEffect(() => {
    if (form.material_precio_m2 > 0) {
      setItems(prev => prev.map(it => it.precio_m2 ? it : { ...it, precio_m2: form.material_precio_m2 }));
    }
  }, [form.material_precio_m2]);

  const handleMaterialChange = (value) => {
    if (value === '__otro__') {
      setMaterialOtro(true);
      setForm(prev => ({ ...prev, material: '', material_precio_m2: 0, color_tipo: '', espesor: '' }));
    } else {
      const m = materiales.find(mat => mat.nombre === value);
      const pm2 = m?.precio_m2 || 0;
      setForm(prev => ({
        ...prev, material: value, material_precio_m2: pm2,
        color_tipo: m?.color || '', espesor: m?.espesor_disponible || ''
      }));
    }
  };

  const updateItem = (idx, field, val) => {
    setItems(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], [field]: val };
      const it = next[idx];
      if (field === 'largo' || field === 'ancho') {
        it.m2 = (it.largo || 0) * (it.ancho || 0);
      }
      it.subtotal = (it.m2 || 0) * (it.cantidad || 0) * (it.precio_m2 || 0);
      return next;
    });
  };

  const addItem = () => setItems(prev => [...prev, emptyItem(form.material_precio_m2 || 0)]);
  const removeItem = (idx) => setItems(prev => prev.filter((_, i) => i !== idx));

  const updateAdicional = (idx, field, val) => {
    setAdicionales(prev => {
      const next = [...prev];
      next[idx] = { ...next[idx], [field]: val };
      const it = next[idx];
      it.subtotal = (it.cantidad || 0) * (it.precio_unitario || 0);
      return next;
    });
  };

  const addAdicional = () => setAdicionales(prev => [...prev, emptyAdicional()]);
  const removeAdicional = (idx) => setAdicionales(prev => prev.filter((_, i) => i !== idx));

  useEffect(() => {
    const subMat = items.reduce((sum, it) => sum + (it.subtotal || 0), 0);
    const subAdic = adicionales.reduce((sum, ad) => sum + (ad.subtotal || 0), 0);
    setForm(prev => ({
      ...prev,
      subtotal_materiales: subMat,
      subtotal_servicios: subAdic,
      total: subMat + subAdic
    }));
  }, [items, adicionales]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = {
        ...form,
        cliente_id: Number(form.cliente_id),
        fecha_estimada_entrega: form.fecha_estimada_entrega || null,
        items: items.map(it => ({
          sector: it.sector, zocalo: it.zocalo, frente: it.frente,
          largo: Number(it.largo), ancho: Number(it.ancho),
          m2: Number(it.m2), cantidad: Number(it.cantidad),
          precio_m2: Number(it.precio_m2), subtotal: Number(it.subtotal)
        })),
        adicionales: adicionales.map(ad => ({
          concepto: ad.concepto, detalle: ad.detalle || '',
          cantidad: Number(ad.cantidad),
          precio_unitario: Number(ad.precio_unitario), subtotal: Number(ad.subtotal)
        })),
      };
      if (isEdit) {
        await updatePresupuesto(id, payload);
      } else {
        await createPresupuesto(payload);
      }
      navigate('/presupuestos');
    } catch (err) {
      alert('Error al guardar');
    } finally {
      setSaving(false);
    }
  };

  const handleConvertir = async () => {
    if (!window.confirm('¿Convertir este presupuesto aprobado en orden de trabajo?')) return;
    try {
      await convertirAOrden(id);
      navigate('/ordenes');
    } catch (err) {
      alert(err.response?.data?.detail || 'Error');
    }
  };

  if (loading) return <Loading />;

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 24 }}>
        <h1 style={{ fontSize: 24, fontWeight: 700 }}>{isEdit ? 'Editar Presupuesto' : 'Nuevo Presupuesto'}</h1>
        <div style={{ display: 'flex', gap: 8 }}>
          {isEdit && (
            <button className="btn btn-success" onClick={handleConvertir}><Send size={16} /> Convertir a Orden</button>
          )}
        </div>
      </div>

      <form onSubmit={handleSubmit}>
        <div style={{ display: 'grid', gap: 20, maxWidth: 1100 }}>
          {/* Cliente */}
          <div className="card">
            <h3 className="section-title">Datos del Cliente</h3>
            <div className="form-group">
              <label>Cliente *</label>
              <select className="input" required value={form.cliente_id} onChange={(e) => setForm({ ...form, cliente_id: e.target.value })}>
                <option value="">Seleccionar cliente...</option>
                {clientes.map((c) => <option key={c.id} value={c.id}>{c.nombre}</option>)}
              </select>
            </div>
          </div>

          {/* Material */}
          <div className="card">
            <h3 className="section-title">Material</h3>
            <div className="form-row">
              <div className="form-group" style={{ flex: 2 }}>
                <label>Material</label>
                {!materialOtro ? (
                  <select className="input" value={form.material} onChange={(e) => handleMaterialChange(e.target.value)}>
                    <option value="">Seleccionar material...</option>
                    {materiales.map((m) => <option key={m.id} value={m.nombre}>{m.nombre} - {m.color || ''}</option>)}
                    <option value="__otro__">Otro...</option>
                  </select>
                ) : (
                  <div style={{ display: 'flex', gap: 8 }}>
                    <input className="input" placeholder="Escribir material..." value={form.material} onChange={(e) => setForm({ ...form, material: e.target.value })} />
                    <button type="button" className="btn btn-outline" onClick={() => { setMaterialOtro(false); setForm({ ...form, material: '', material_precio_m2: 0 }); }}>Volver</button>
                  </div>
                )}
              </div>
              <div className="form-group">
                <label>Precio m²</label>
                <input className="input" type="number" step="0.01" value={form.material_precio_m2} onChange={(e) => setForm({ ...form, material_precio_m2: Number(e.target.value) })} />
              </div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Color / Tipo</label><input className="input" value={form.color_tipo} disabled={!!form.material && !materialOtro} onChange={(e) => setForm({ ...form, color_tipo: e.target.value })} /></div>
              <div className="form-group"><label>Espesor</label><input className="input" value={form.espesor} disabled={!!form.material && !materialOtro} onChange={(e) => setForm({ ...form, espesor: e.target.value })} /></div>
            </div>
          </div>

          {/* Piezas / Cómputo */}
          <div className="card">
            <h3 className="section-title">Cómputo de Piezas</h3>
            <div style={{ overflowX: 'auto' }}>
              <table className="table" style={{ width: '100%', minWidth: 900 }}>
                <thead>
                  <tr>
                    <th>Sector / Zócalo / Frente</th>
                    <th>Largo (m)</th>
                    <th>Ancho (m)</th>
                    <th>M²</th>
                    <th>Cant.</th>
                    <th>Precio M²</th>
                    <th>Subtotal</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {items.map((it, i) => (
                    <tr key={i}>
                      <td style={{ minWidth: 200 }}>
                        <select className="input" value={SECTORES_SUGERIDOS.includes(it.sector) ? it.sector : (it.sector ? 'Otro' : '')} onChange={(e) => {
                          const v = e.target.value;
                          if (v === 'Otro') updateItem(i, 'sector', '__edit__');
                          else updateItem(i, 'sector', v);
                        }}>
                          <option value="">Sector...</option>
                          {SECTORES_SUGERIDOS.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                        {!SECTORES_SUGERIDOS.includes(it.sector) && it.sector && (
                          <input className="input" style={{ marginTop: 4 }} placeholder="Escribir sector..." value={it.sector === '__edit__' ? '' : it.sector} onChange={(e) => updateItem(i, 'sector', e.target.value)} />
                        )}
                        <select className="input" style={{ marginTop: 4 }} value={it.zocalo} onChange={(e) => updateItem(i, 'zocalo', e.target.value)}>
                          <option value="">Zócalo...</option>
                          <option value="SI">SI</option>
                          <option value="NO">NO</option>
                        </select>
                        <select className="input" style={{ marginTop: 4 }} value={it.frente} onChange={(e) => updateItem(i, 'frente', e.target.value)}>
                          <option value="">Frente...</option>
                          <option value="SIN FRENTE">SIN FRENTE</option>
                          <option value="INGLETADO 45°">INGLETADO 45°</option>
                          <option value="CLÁSICO RASADO">CLÁSICO RASADO</option>
                          <option value="CLÁSICO HUNDIDO">CLÁSICO HUNDIDO</option>
                          <option value="DOBLE RASADO">DOBLE RASADO</option>
                          <option value="DOBLE HUNDIDO">DOBLE HUNDIDO</option>
                        </select>
                      </td>
                      <td><input className="input" type="number" step="0.001" min="0" value={it.largo || ''} onChange={(e) => updateItem(i, 'largo', Number(e.target.value))} /></td>
                      <td><input className="input" type="number" step="0.001" min="0" value={it.ancho || ''} onChange={(e) => updateItem(i, 'ancho', Number(e.target.value))} /></td>
                      <td style={{ fontWeight: 600 }}>{it.m2.toFixed(3)}</td>
                      <td><input className="input" type="number" min="1" value={it.cantidad} onChange={(e) => updateItem(i, 'cantidad', Number(e.target.value))} /></td>
                      <td><input className="input" type="number" step="0.01" min="0" value={it.precio_m2 || ''} onChange={(e) => updateItem(i, 'precio_m2', Number(e.target.value))} /></td>
                      <td style={{ fontWeight: 600 }}>{formatCurrency(it.subtotal)}</td>
                      <td>
                        {items.length > 1 && (
                          <button type="button" className="btn btn-outline-danger btn-sm" onClick={() => removeItem(i)}>
                            <Trash2 size={14} />
                          </button>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <button type="button" className="btn btn-outline btn-sm" style={{ marginTop: 8 }} onClick={addItem}>
              <Plus size={14} /> Agregar pieza
            </button>
          </div>

          {/* Adicionales */}
          <div className="card">
            <h3 className="section-title">Adicionales / Servicios</h3>
            <div style={{ overflowX: 'auto' }}>
              <table className="table" style={{ width: '100%', minWidth: 700 }}>
                <thead>
                  <tr>
                    <th>Concepto</th>
                    <th>Detalle</th>
                    <th>Cantidad</th>
                    <th>Precio Unit.</th>
                    <th>Subtotal</th>
                    <th></th>
                  </tr>
                </thead>
                <tbody>
                  {adicionales.map((ad, i) => (
                    <tr key={i}>
                      <td>
                        <select className="input" value={ADICIONALES_SUGERIDOS.includes(ad.concepto) ? ad.concepto : (ad.concepto ? 'Otro' : '')} onChange={(e) => {
                          const v = e.target.value;
                          if (v === 'Otro') updateAdicional(i, 'concepto', '__edit__');
                          else updateAdicional(i, 'concepto', v);
                        }}>
                          <option value="">Seleccionar...</option>
                          {ADICIONALES_SUGERIDOS.map(s => <option key={s} value={s}>{s}</option>)}
                        </select>
                        {!ADICIONALES_SUGERIDOS.includes(ad.concepto) && ad.concepto && (
                          <input className="input" style={{ marginTop: 4 }} placeholder="Escribir concepto..." value={ad.concepto === '__edit__' ? '' : ad.concepto} onChange={(e) => updateAdicional(i, 'concepto', e.target.value)} />
                        )}
                      </td>
                      <td>
                        {ad.concepto === 'TERMINACIÓN FRENTE' ? (
                          <select className="input" value={ad.detalle} onChange={(e) => updateAdicional(i, 'detalle', e.target.value)}>
                            <option value="">Seleccionar tipo...</option>
                            {TIPOS_FRENTE.map(t => <option key={t} value={t}>{t}</option>)}
                          </select>
                        ) : (
                          <input className="input" value={ad.detalle} onChange={(e) => updateAdicional(i, 'detalle', e.target.value)} />
                        )}
                      </td>
                      <td><input className="input" type="number" min="1" value={ad.cantidad} onChange={(e) => updateAdicional(i, 'cantidad', Number(e.target.value))} /></td>
                      <td><input className="input" type="number" step="0.01" min="0" value={ad.precio_unitario || ''} onChange={(e) => updateAdicional(i, 'precio_unitario', Number(e.target.value))} /></td>
                      <td style={{ fontWeight: 600 }}>{formatCurrency(ad.subtotal)}</td>
                      <td>
                        <button type="button" className="btn btn-outline-danger btn-sm" onClick={() => removeAdicional(i)}>
                          <Trash2 size={14} />
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <button type="button" className="btn btn-outline btn-sm" style={{ marginTop: 8 }} onClick={addAdicional}>
              <Plus size={14} /> Agregar adicional
            </button>
          </div>

          {/* Resumen */}
          <div className="card">
            <h3 className="section-title">Resumen</h3>
            <div style={{ maxWidth: 400 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 0', borderBottom: '1px solid #e2e8f0' }}>
                <span>Materiales</span>
                <span style={{ fontWeight: 600 }}>{formatCurrency(form.subtotal_materiales)}</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 0', borderBottom: '1px solid #e2e8f0' }}>
                <span>Servicios / Adicionales</span>
                <span style={{ fontWeight: 600 }}>{formatCurrency(form.subtotal_servicios)}</span>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between', padding: '8px 0', fontSize: 18, fontWeight: 700 }}>
                <span>Total</span>
                <span>{formatCurrency(form.total)}</span>
              </div>
            </div>
          </div>

          {/* Condiciones comerciales */}
          <div className="card">
            <h3 className="section-title">Condiciones Comerciales</h3>
            <div className="form-group">
              <textarea className="input" rows={4} value={form.condiciones_comerciales} onChange={(e) => setForm({ ...form, condiciones_comerciales: e.target.value })} placeholder="Ej: Envío sin cargo La Plata y alrededores&#10;No incluye descarga&#10;No realizamos colocaciones&#10;Plazo de entrega: ...&#10;Forma de pago: ..." />
            </div>
          </div>

          {/* Información Comercial */}
          <div className="card">
            <h3 className="section-title">Información Comercial</h3>
            <div className="form-row">
              <div className="form-group"><label>Forma de Pago</label>
                <select className="input" value={form.forma_pago} onChange={(e) => setForm({ ...form, forma_pago: e.target.value })}>
                  <option value="">Seleccionar...</option>
                  {formasPago.map((f) => <option key={f} value={f}>{f}</option>)}
                </select>
              </div>
              <div className="form-group"><label>Validez</label><input className="input" value={form.validez} onChange={(e) => setForm({ ...form, validez: e.target.value })} /></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Entrega aproximada</label><input className="input" value={form.entrega_aproximada} onChange={(e) => setForm({ ...form, entrega_aproximada: e.target.value })} /></div>
              <div className="form-group"><label>Fecha estimada de entrega</label><input className="input" type="date" value={form.fecha_estimada_entrega} onChange={(e) => setForm({ ...form, fecha_estimada_entrega: e.target.value })} /></div>
            </div>
          </div>

          {/* Observaciones */}
          <div className="card">
            <h3 className="section-title">Observaciones</h3>
            <div className="form-group">
              <textarea className="input" rows={3} value={form.observaciones} onChange={(e) => setForm({ ...form, observaciones: e.target.value })} />
            </div>
          </div>

          <div style={{ display: 'flex', gap: 12, justifyContent: 'flex-end' }}>
            <button type="button" className="btn btn-outline" onClick={() => navigate('/presupuestos')}>Cancelar</button>
            <button type="submit" className="btn btn-primary" disabled={saving}>
              <Save size={16} /> {saving ? 'Guardando...' : (isEdit ? 'Actualizar' : 'Crear Presupuesto')}
            </button>
          </div>
        </div>
      </form>
    </div>
  );
}
